import{_ as t,o as l,c as e,a3 as i}from"./chunks/framework.BTFg6ESq.js";const g=JSON.parse('{"title":"Agent 工具调用","description":"","frontmatter":{},"headers":[],"relativePath":"user-guide/advanced/agent-tool-calling.md","filePath":"user-guide/advanced/agent-tool-calling.md","lastUpdated":1780241474000}'),n={name:"user-guide/advanced/agent-tool-calling.md"};function o(d,a,r,s,h,p){return l(),e("div",null,[...a[0]||(a[0]=[i('<h1 id="agent-工具调用" tabindex="-1">Agent 工具调用 <a class="header-anchor" href="#agent-工具调用" aria-label="Permalink to &quot;Agent 工具调用&quot;">​</a></h1><p>Agent 工具调用让 AI 不只回答文字，还能调用 AIO Hub 内置工具、插件方法和 Skill 能力。它适合让 AI 检索知识库、分析目录、处理文件、执行检查或调用你安装的扩展服务。</p><h2 id="工作方式" tabindex="-1">工作方式 <a class="header-anchor" href="#工作方式" aria-label="Permalink to &quot;工作方式&quot;">​</a></h2><p>一次工具调用通常包含这些步骤：</p><ol><li>Agent 在系统提示词中看到可用工具定义。</li><li>AI 回复中生成工具请求。</li><li>AIO Hub 解析请求并检查审批策略。</li><li>用户批准或系统自动批准。</li><li>工具执行，结果被写回对话。</li><li>AI 根据结果继续回复，或进入下一轮工具调用。</li></ol><p>这套循环有最大轮次限制，避免模型连续调用工具停不下来。</p><h2 id="开启工具调用" tabindex="-1">开启工具调用 <a class="header-anchor" href="#开启工具调用" aria-label="Permalink to &quot;开启工具调用&quot;">​</a></h2><ol><li>打开 LLM Chat。</li><li>进入 Agent 编辑器或聊天输入区的工具调用设置。</li><li>打开工具调用总开关。</li><li>选择默认策略：手动审批或自动审批。</li><li>按工具启用你希望 Agent 使用的能力。</li></ol><p>首次使用建议选择手动审批。等你确认某些工具足够安全、参数稳定后，再为它们开启自动批准。</p><h2 id="审批策略" tabindex="-1">审批策略 <a class="header-anchor" href="#审批策略" aria-label="Permalink to &quot;审批策略&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">策略</th><th style="text-align:left;">适合场景</th><th style="text-align:left;">说明</th></tr></thead><tbody><tr><td style="text-align:left;">手动审批</td><td style="text-align:left;">文件操作、网络请求、插件工具、不熟悉的 Agent</td><td style="text-align:left;">每个请求都需要你确认</td></tr><tr><td style="text-align:left;">自动审批</td><td style="text-align:left;">只读查询、低风险统计、你信任的工具</td><td style="text-align:left;">命中白名单后自动执行</td></tr><tr><td style="text-align:left;">静默执行</td><td style="text-align:left;">只想拿工具结果，不希望继续生成多轮回复</td><td style="text-align:left;">当前轮工具执行结束后停止循环</td></tr></tbody></table><p>审批栏中可以逐项批准、全部允许、全部拒绝，也可以切换静默模式。</p><h2 id="控制工具范围" tabindex="-1">控制工具范围 <a class="header-anchor" href="#控制工具范围" aria-label="Permalink to &quot;控制工具范围&quot;">​</a></h2><p>Agent 的工具调用配置可以限制：</p><ul><li>是否启用工具调用。</li><li>最大循环轮次。</li><li>单次调用超时时间。</li><li>是否允许并行执行同一轮多个请求。</li><li>默认是否启用新发现的工具。</li><li>每个工具是否可用。</li><li>每个工具是否自动批准。</li></ul><p>如果你要构建稳定的工作流，建议只打开必要工具，而不是让 Agent 看到全部能力。</p><h2 id="使用-skill" tabindex="-1">使用 Skill <a class="header-anchor" href="#使用-skill" aria-label="Permalink to &quot;使用 Skill&quot;">​</a></h2><p>Skill 会以工具形式被披露给 Agent。模型先看到 Skill 摘要，判断需要时再激活完整说明，随后按需读取资源或执行脚本。</p><p>适合 Skill 的场景包括：</p><ul><li>某类项目的固定工作流程。</li><li>本地脚本自动化。</li><li>复杂工具的使用说明和操作模板。</li><li>团队内部标准化处理步骤。</li></ul><p>由于 Skill 可能执行脚本或读取文件，建议在不熟悉 Skill 内容时保留手动审批。</p><h2 id="调试工具调用" tabindex="-1">调试工具调用 <a class="header-anchor" href="#调试工具调用" aria-label="Permalink to &quot;调试工具调用&quot;">​</a></h2><p>如果工具调用没有按预期执行，可以这样排查：</p><ol><li>确认当前 Agent 已开启工具调用。</li><li>检查目标工具是否启用。</li><li>查看是否被审批栏拒绝或超时。</li><li>打开工具调用测试工具，验证工具定义和参数格式。</li><li>查看日志管理器，确认执行器是否记录了错误。</li><li>对已有助手消息使用重新解析，让系统重新识别其中的工具请求。</li></ol><h2 id="提示词建议" tabindex="-1">提示词建议 <a class="header-anchor" href="#提示词建议" aria-label="Permalink to &quot;提示词建议&quot;">​</a></h2><p>让 Agent 使用工具时，描述目标、边界和风险偏好：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>请先检查项目目录结构，再总结文档缺口。只读取文件，不要修改任何内容。需要调用工具时请先等待我确认。</span></span></code></pre></div><p>对于可自动执行的安全任务，可以明确授权：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>你可以自动调用只读分析工具，最多循环 3 轮。涉及写文件、删除文件或网络请求时必须先询问我。</span></span></code></pre></div><h2 id="常见问题" tabindex="-1">常见问题 <a class="header-anchor" href="#常见问题" aria-label="Permalink to &quot;常见问题&quot;">​</a></h2><h3 id="为什么-ai-明明说要调用工具-却没有执行" tabindex="-1">为什么 AI 明明说要调用工具，却没有执行？ <a class="header-anchor" href="#为什么-ai-明明说要调用工具-却没有执行" aria-label="Permalink to &quot;为什么 AI 明明说要调用工具，却没有执行？&quot;">​</a></h3><p>可能是 Agent 未启用工具调用、工具不在可用列表中、模型输出格式不符合协议，或该请求被审批策略拦截。先查看审批栏和日志管理器。</p><h3 id="自动批准安全吗" tabindex="-1">自动批准安全吗？ <a class="header-anchor" href="#自动批准安全吗" aria-label="Permalink to &quot;自动批准安全吗？&quot;">​</a></h3><p>自动批准取决于工具能力。只读查询通常风险较低；写文件、执行命令、访问网络或调用第三方插件时应谨慎。</p><h3 id="工具调用结果会进入上下文吗" tabindex="-1">工具调用结果会进入上下文吗？ <a class="header-anchor" href="#工具调用结果会进入上下文吗" aria-label="Permalink to &quot;工具调用结果会进入上下文吗？&quot;">​</a></h3><p>会。执行结果会按协议追加到对话路径中，模型会基于结果继续生成。上下文管道和 Token 限制仍会影响最终注入内容。</p><h3 id="可以限制-ai-最多调用几轮吗" tabindex="-1">可以限制 AI 最多调用几轮吗？ <a class="header-anchor" href="#可以限制-ai-最多调用几轮吗" aria-label="Permalink to &quot;可以限制 AI 最多调用几轮吗？&quot;">​</a></h3><p>可以。在 Agent 的工具调用配置中设置最大迭代次数。默认限制用于防止无限循环。</p>',38)])])}const u=t(n,[["render",o]]);export{g as __pageData,u as default};
